parameters.jsCode:
let raw =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.message ||
  '{}';

raw = String(raw)
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed = {};

try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    route: 'unknown',
    language: 'en',
    reason: 'Could not parse router JSON',
    confidence: 0
  };
}

function safeJsonParse(value, fallback = {}) {
  if (!value) return fallback;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(value);
  } catch (error) {
    return fallback;
  }
}

const guestMessage = String(
  $('Normalize Incoming Message').first().json.guest_message ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Message Text'] ||
  ''
).trim();

const guestMessageLower = guestMessage.toLowerCase();

const conversationFields =
  $('Search Conversation').first().json.fields || {};

const existingSession = safeJsonParse(
  conversationFields['Session State'],
  {}
);

let session = {
  ...existingSession,
  ...(parsed.session || {})
};

// NEW BOOKING OVERRIDE
const wantsNewBooking =
  /\b(new booking|another booking|separate booking|book again|create a new one|make a new booking|new reservation|another reservation|new one)\b/i.test(guestMessageLower);

if (wantsNewBooking) {
  session = {
    intent: 'booking_request',
    language: session.language || parsed.language || conversationFields.Language || 'en',
    needs_human: false,
    previous_hold_id: session.current_hold_id || conversationFields['Current Hold ID'] || null,
    current_hold_id: null,
    pending_action: 'collect_booking_details'
  };

  parsed.route = 'booking_flow';
  parsed.reason = 'Guest explicitly requested a new booking';
  parsed.confidence = Math.max(Number(parsed.confidence || 0), 0.98);
}

// ALTERNATIVE DATE SELECTION
function choseOptionOne(text) {
  return /\b(1|one|first|first option|option 1|number 1|the first one|first one)\b/i.test(text);
}

function choseOptionTwo(text) {
  return /\b(2|two|second|second option|option 2|number 2|the second one|second one)\b/i.test(text);
}

function choseOptionThree(text) {
  return /\b(3|three|third|third option|option 3|number 3|the third one|third one)\b/i.test(text);
}

function getAlternativeByOption(alternatives, optionNumber) {
  return (
    alternatives.find(a => Number(a.option) === Number(optionNumber)) ||
    alternatives[optionNumber - 1] ||
    null
  );
}

if (
  !wantsNewBooking &&
  (
    session.pending_action === 'choose_alternative_dates' ||
    conversationFields['Pending Action'] === 'choose_alternative_dates' ||
    conversationFields['Conversation Stage'] === 'no_availability_alternatives'
  )
) {
  const alternatives =
    session.alternative_dates ||
    session.alternatives ||
    [];

  let selectedAlternative = null;

  if (choseOptionOne(guestMessageLower)) {
    selectedAlternative = getAlternativeByOption(alternatives, 1);
  } else if (choseOptionTwo(guestMessageLower)) {
    selectedAlternative = getAlternativeByOption(alternatives, 2);
  } else if (choseOptionThree(guestMessageLower)) {
    selectedAlternative = getAlternativeByOption(alternatives, 3);
  }

  if (
    selectedAlternative &&
    selectedAlternative.check_in &&
    selectedAlternative.check_out
  ) {
    session = {
      ...session,
      check_in: selectedAlternative.check_in,
      check_out: selectedAlternative.check_out,
      selected_alternative_option: selectedAlternative.option || null,
      selected_alternative_dates: selectedAlternative,
      pending_action: 'collect_guest_details'
    };

    parsed.route = 'booking_flow';
    parsed.reason = 'Guest selected alternative availability dates';
    parsed.confidence = Math.max(Number(parsed.confidence || 0), 0.95);
  }
}

// NORMALIZE ROUTER FIELDS INTO SESSION
if (parsed.check_in && !session.check_in) {
  session.check_in = parsed.check_in;
}

if (parsed.check_out && !session.check_out) {
  session.check_out = parsed.check_out;
}

if (parsed.guest_count && !session.guest_count) {
  session.guest_count = Number(parsed.guest_count);
}

if (parsed.guests && !session.guest_count) {
  session.guest_count = Number(parsed.guests);
}

if (parsed.email && !session.email) {
  session.email = parsed.email;
}

if (parsed.name && !session.name) {
  session.name = parsed.name;
}

return {
  json: {
    route: parsed.route || 'unknown',
    language:
      parsed.language ||
      conversationFields.Language ||
      session.language ||
      'en',
    reason: parsed.reason || '',
    confidence: Number(parsed.confidence || 0),
    intent: parsed.intent || parsed.route || 'unknown',
    guest_message: guestMessage,
    session
  }
};

const data = $input.first().json;
const session = data.session || {};

const inboundPhone =
  $('Normalize Incoming Message').first().json.phone ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Conversation Phone'] ||
  '';

const guestCount = Number(
  session.guest_count ||
  data.guest_count ||
  1
);

const multiRoomRequired =
  data.multi_room_required === true ||
  data.availability_type === 'multi_room';

const selectedRoom = data.selected_room || {};

const holdRoomId = multiRoomRequired
  ? ''
  : selectedRoom.room_id || data.hold_room_id || '';

const holdRoomName = multiRoomRequired
  ? 'Multiple rooms'
  : selectedRoom.room_name || data.hold_room_name || '';

const today = new Date().toISOString().slice(2, 10).replace(/-/g, '');

return [
  {
    json: {
      ...data,

      hold_room_id: holdRoomId,
      hold_room_name: holdRoomName,

      hold_booking_id:
        'WH-' + today + '-' + Math.floor(1000 + Math.random() * 9000),

      guest_name: session.name || null,
      guest_email: session.email || null,
      guest_phone: session.phone || inboundPhone || null,

      guest_count: guestCount,

      has_guest_details:
        !!session.name && !!session.email,
      should_run_stripe_payment: (() => {
        try {
          const resolver = $('Code - Booking State Resolver').first().json || {};
          if (resolver.staged_contact?.apply_after_hold === true) return true;
          if (resolver.resolved_sub_route === 'booking_full_capture_then_payment') {
            return !!(session.name && session.email);
          }
        } catch (_) {}
        return !!(session.name && session.email);
      })()
    }
  }
];

const atHold = ($('Create Booking Hold').isExecuted ? $('Create Booking Hold') : $('Code - DRY RUN Stub (Create Booking Hold)')).first().json;
const backfill = ($('Postgres - Backfill Booking AT Record Id').isExecuted ? $('Postgres - Backfill Booking AT Record Id') : $('Code - DRY RUN Stub (Postgres - Backfill Booking AT Record Id)')).first().json || {};
const availability =
  $('Code - Map PG Availability').first().json ||
  $('Code - Check Bed Availability - WA').first().json;
const prepareHold = $('Code - Prepare Hold Records').first().json;
const pgHold = $('Code - Validate PG Hold').first().json;
const resolver = $('Code - Booking State Resolver').first().json;

const bookingCode =
  atHold.fields?.['Booking ID'] ||
  atHold['Booking ID'] ||
  pgHold.booking_code ||
  prepareHold.hold_booking_id ||
  '';

const holdRecordId = atHold.id || '';
const roomIds = [
  atHold.fields?.['Room ID'] ||
    atHold.fields?.['hold_room_id'] ||
    availability.hold_room_id ||
    availability.selected_room?.room_id ||
    pgHold.primary_room_code ||
    '',
];
const roomNames = [
  atHold.fields?.['Room Name'] ||
    availability.hold_room_name ||
    availability.selected_room?.room_name ||
    '',
];

const hasGuestDetails = !!prepareHold.has_guest_details;
const applyAfterHold = resolver.staged_contact?.apply_after_hold === true;

return [
  {
    json: {
      ...availability,
      holds_created: true,
      hold_booking_ids: bookingCode ? [bookingCode] : [],
      hold_room_ids: roomIds,
      hold_room_names: roomNames,
      hold_count: 1,
      hold_record_id: holdRecordId,
      pg_booking_id: pgHold.booking_id || backfill.booking_id || null,
      booking_code: bookingCode,
      has_guest_details: hasGuestDetails,
      should_run_stripe_payment:
        applyAfterHold ||
        prepareHold.should_run_stripe_payment === true ||
        hasGuestDetails,
      staged_contact_apply_after_hold: applyAfterHold,
      pg_hold_created: pgHold.pg_created === true,
      pg_hold_updated: pgHold.pg_updated === true,
      airtable_record_id: backfill.airtable_record_id || atHold.id || null,
    },
  },
];

const data = $input.first().json;

const session = data.session || {};

const phone =
  $('Normalize Incoming Message').first().json.phone ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Conversation Phone'] ||
  '';

const requestedCheckIn = new Date(session.check_in);
const requestedCheckOut = new Date(session.check_out);

const bookings = data.bookings_seen || [];

const existingHolds = bookings.filter(booking => {
  const bookingPhone = String(booking.Phone || '').trim();
  const status = String(booking.Status || '').toLowerCase().trim();

  if (bookingPhone !== phone) return false;
  if (status !== 'hold') return false;

  const existingCheckIn = new Date(booking['Check In']);
  const existingCheckOut = new Date(booking['Check Out']);

  return existingCheckIn < requestedCheckOut && existingCheckOut > requestedCheckIn;
});

return [
  {
    json: {
      ...data,
      phone,
      existing_active_hold_found: existingHolds.length > 0,
      existing_holds: existingHolds,
      existing_hold_ids: existingHolds.map(h => h['Booking ID'])
    }
  }
];

const now = new Date();

const expired = $input.all().filter(item => {
  const holdExpiresAt =
    item.json.fields?.['Hold Expires At'] ||
    item.json['Hold Expires At'];

  if (!holdExpiresAt) return false;

  return new Date(holdExpiresAt) <= now;
});

return expired;

const message = String(
  $('Normalize Incoming Message').first().json.guest_message ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Message Text'] ||
  ''
).trim();

const phone =
  $('Normalize Incoming Message').first().json.phone ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Conversation Phone'] ||
  '';

function cleanJson(raw) {
  return String(raw || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function escapeRegex(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function stripConnectorWords(value) {
  return String(value || '')
    .replace(/\b(and|und|y|e|et|con|with)\b\s*$/i, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractBestNameBeforeEmail(rawMessage, email) {
  if (!rawMessage || !email) return null;

  const parts = String(rawMessage).split(email);
  const beforeEmail = String(parts[0] || '').trim();

  if (!beforeEmail) return null;

  let candidate = beforeEmail
    .replace(/\b(my name is|name is|this is|i am|i'm|ich bin|mein name ist|soy|me llamo|mi nombre es|sono|mi chiamo|je suis|je m'appelle)\b/gi, ' ')
    .replace(/\b(my email is|email is|email|mail|correo|e-mail|gmail|hotmail|outlook)\b/gi, ' ')
    .replace(/[,:;/|()[\]{}<>]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  candidate = stripConnectorWords(candidate);

  if (!candidate) return null;

  const words = candidate.split(/\s+/);

  // If the user wrote a sentence before the email, only keep the last few likely-name words.
  // Examples:
  // "my name is Jim and jim@gmail.com" -> "Jim"
  // "it's for Maria Garcia and maria@gmail.com" -> "Maria Garcia"
  if (words.length > 4) {
    candidate = words.slice(-3).join(' ');
  }

  return candidate;
}

function cleanName(value) {
  let name = String(value || '').trim();

  if (!name) return null;

  // Remove emails
  for (const email of emails) {
    name = name.replace(new RegExp(escapeRegex(email), 'gi'), ' ');
  }

  // Remove booking ID
  if (bookingId) {
    name = name.replace(new RegExp(escapeRegex(bookingId), 'gi'), ' ');
  }

  // Common labels / filler
  name = name
    .replace(/\b(my name is|name is|this is|i am|i'm|ich bin|mein name ist|soy|me llamo|mi nombre es|sono|mi chiamo|je suis|je m'appelle)\b/gi, ' ')
    .replace(/\b(email is|my email is|email|mail|correo|e-mail|gmail|hotmail|outlook)\b/gi, ' ')
    .replace(/\b(thanks|thank you|danke|gracias|grazie|merci|perfect|perfekt|perfecto|ok|okay|yes|yep|yeah|ja|sí|si|oui)\b/gi, ' ')
    .replace(/[,:;/|()[\]{}<>]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  name = stripConnectorWords(name);

  if (!name) return null;

  // Remove dangling connector again after punctuation cleanup.
  name = stripConnectorWords(name);

  const words = name.split(/\s+/);

  // Avoid saving full sentences
  if (words.length > 6) return null;

  const looksLikeSentence =
    /\b(want|book|stay|arrive|change|cancel|möchte|wollen|quiero|queremos|vorrei|vogliamo|veux|voulons)\b/i.test(name);

  if (looksLikeSentence) return null;

  return name;
}

// Read AI extraction if present
const aiRaw =
  $('AI - Extract Guest Details').first().json.text ||
  $('AI - Extract Guest Details').first().json.output ||
  $('AI - Extract Guest Details').first().json.response ||
  '{}';

let ai = {};
try {
  ai = JSON.parse(cleanJson(aiRaw));
} catch (e) {
  ai = {};
}

// Regex backup
const emailMatches =
  message.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi) || [];

const emails = [...new Set(emailMatches.map(e => e.trim()))];

const primaryEmail =
  emails[0] ||
  ai.guest_email ||
  ai.email ||
  null;

const bookingIdMatch = message.match(/WH-[A-Za-z0-9-]+/i);
const bookingId = bookingIdMatch ? bookingIdMatch[0] : (ai.booking_id || ai.bookingId || null);

// Best deterministic case:
// "Jim and jim@gmail.com" should become name = Jim, email = jim@gmail.com
let nameBeforeEmail = primaryEmail ? extractBestNameBeforeEmail(message, primaryEmail) : null;

// Prefer the name before email when it exists, because AI often returns "Jim and"
let guestName = cleanName(nameBeforeEmail);

// Then try AI guest_name
if (!guestName) {
  guestName = cleanName(ai.guest_name || ai.name || null);
}

// Fallback: derive from message before the email
if (!guestName && primaryEmail) {
  const beforeEmail = message.split(primaryEmail)[0].trim();
  guestName = cleanName(beforeEmail);
}

// Final fallback: remove emails and labels from full message
if (!guestName) {
  let fallback = message;

  for (const email of emails) {
    fallback = fallback.replace(new RegExp(escapeRegex(email), 'gi'), ' ');
  }

  if (bookingId) {
    fallback = fallback.replace(new RegExp(escapeRegex(bookingId), 'gi'), ' ');
  }

  guestName = cleanName(fallback);
}

return [
  {
    json: {
      guest_name: guestName,
      guest_email: primaryEmail,
      guest_emails_all: emails,
      guest_phone: phone,
      booking_id: bookingId
    }
  }
];

