parameters.jsCode:
const verifyToken = $json.query["hub.verify_token"];
const challenge = $json.query["hub.challenge"];

if (verifyToken === "wolfhouse_verify_token") {
  return [
    {
      json: {
        challenge
      }
    }
  ];
}

throw new Error("Invalid verify token");

const messages = $input.all()
  .map(item => item.json.fields || item.json)
  .reverse();

const memoryText = messages.map(m => {
  const direction = m.Direction || '';
  const type = m['Message Type'] || '';
  const text = m['Message Text'] || '';
  return `${direction}/${type}: ${text}`;
}).join('\n');

// Prefer normalized real/test input.
// Fallback to Create Inbound Message output.
// Final fallback to Set Fake Guest Message if you still use it in some test runs.
let original = {};

try {
  original = $('Code - Normalize Incoming Message').first().json;
} catch (e) {
  try {
    const inbound = ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields || {};
    original = {
      source: inbound.Source || 'whatsapp',
      phone: inbound['Conversation Phone'] || '',
      guest_message: inbound['Message Text'] || '',
      whatsapp_message_id: inbound['WhatsApp Message ID'] || ''
    };
  } catch (e2) {
    try {
      original = $('Set Fake Guest Message').first().json;
    } catch (e3) {
      original = {};
    }
  }
}

return [{
  json: {
    ...original,
    conversation_memory: memoryText,
    recent_message_count: messages.length
  }
}];

