const message = String(
  $('Normalize Incoming Message').first().json.guest_message ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Message Text'] ||
  ''
);

const phone =
  $('Normalize Incoming Message').first().json.phone ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Conversation Phone'] ||
  '';

const emailMatch = message.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const email = emailMatch ? emailMatch[0] : null;

const bookingIdMatch = message.match(/WH-[A-Za-z0-9-]+/i);
const bookingId = bookingIdMatch ? bookingIdMatch[0] : null;

let name = null;

if (email) {
  name = message
    .replace(email, '')
    .replace(bookingId || '', '')
    .replace(/\b(my name is|name is|email is|my email is|email|booking id is|booking id|booking|thanks|thank you|sweet|cool|great|awesome|perfect|ok|okay|yes|yep|yeah|let'?s do it|book it|i paid|paid|payment done|payment completed)\b/gi, '')
    .replace(/[,:;/|]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  name = name || null;
}

return [
  {
    json: {
      guest_name: name,
      guest_email: email,
      guest_phone: phone,
      booking_id: bookingId
    }
  }
];

