parameters.jsCode:
const data = $('Merge Session State').first().json;
const session = data.session || {};

const bedsRaw = $('Search Active Beds - WA').all();
const assignmentsRaw = $('Search Existing Bed Assignments - WA').all();
const roomsRaw = $('Search Rooms - WA').all();

const guestCount = Math.max(1, Number(session.guest_count || session.guests || 1));

function normalizeSelect(value, fallback = 'unknown') {
  return String(value || fallback)
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_');
}

const requestedRoomType = normalizeSelect(
  session.room_type || session.requested_room_type || 'shared',
  'shared'
);

const roomPreference = normalizeSelect(
  session.room_preference || requestedRoomType,
  requestedRoomType || 'shared'
);

const guestGenderGroup = normalizeSelect(
  session.guest_gender_group_type ||
  session['Guest Gender / Group Type'] ||
  'unknown',
  'unknown'
);

function getLookupValue(value) {
  if (Array.isArray(value)) return value[0];
  return value;
}

function boolValue(value) {
  if (Array.isArray(value)) value = value[0];

  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value === 1;

  if (typeof value === 'string') {
    return ['true', 'yes', '1', 'checked', '👍'].includes(value.toLowerCase());
  }

  return false;
}

function getFieldAny(fields, names, fallback = null) {
  for (const name of names) {
    if (
      fields[name] !== undefined &&
      fields[name] !== null &&
      fields[name] !== ''
    ) {
      return fields[name];
    }
  }

  return fallback;
}

function overlaps(aStart, aEnd, bStart, bEnd) {
  return String(aStart) < String(bEnd) && String(bStart) < String(aEnd);
}

function roomGenderStrategy(room) {
  return String(room.gender_strategy || 'Flexible').trim().toLowerCase();
}

function roomTypeValue(room) {
  return String(room.room_type || '').trim().toLowerCase();
}

function roomIsFemalePreferred(room) {
  const strategy = roomGenderStrategy(room);

  return (
    strategy.includes('female') ||
    strategy.includes('women') ||
    strategy.includes('woman') ||
    strategy.includes('ladies') ||
    strategy.includes('girls')
  );
}

function roomIsMalePreferred(room) {
  const strategy = roomGenderStrategy(room);

  return (
    strategy.includes('male') ||
    strategy.includes('men') ||
    strategy.includes('man') ||
    strategy.includes('boys')
  );
}

function isPrivateLikeRoom(room) {
  const strategy = roomGenderStrategy(room);
  const type = roomTypeValue(room);

  // Important:
  // Can be Matrimonial does NOT make a room private-like.
  // A room is private-like only if the room type/strategy says so or capacity is 2.
  return (
    strategy.includes('private') ||
    type.includes('private') ||
    type.includes('double') ||
    type.includes('family') ||
    Number(room.capacity || 0) === 2
  );
}

function wantsPrivatePlacement() {
  return [
    requestedRoomType,
    roomPreference
  ].some(value =>
    [
      'private',
      'private_room',
      'double',
      'family_room',
      'family',
      'couple_private'
    ].includes(String(value || '').toLowerCase())
  );
}

function wantsFemalePlacement() {
  return (
    roomPreference === 'female_only' ||
    guestGenderGroup === 'female_group' ||
    guestGenderGroup === 'solo_female'
  );
}

function wantsMalePlacement() {
  return (
    roomPreference === 'male_only' ||
    guestGenderGroup === 'male_group' ||
    guestGenderGroup === 'solo_male'
  );
}

const privatePlacementRequested = wantsPrivatePlacement();
const femalePlacementRequested = wantsFemalePlacement();
const malePlacementRequested = wantsMalePlacement();

// Build room metadata from Search Rooms - WA.
const roomsByRecordId = {};
const roomsByRoomId = {};

for (const item of roomsRaw) {
  const fields = item.json.fields || item.json;

  const roomRecordId = item.json.id;
  const roomId = getLookupValue(fields['Room ID']) || fields['Room ID'] || '';

  const fillPriorityRaw = getFieldAny(fields, [
    'Fill Priority',
    'Fill Priority ',
    'Fill priority',
    'Fill priority '
  ], 50);

  const privatePriorityRaw = getFieldAny(fields, [
    'Private Priority',
    'Private Priority ',
    'Private priority',
    'Private priority '
  ], 50);

  const roomData = {
    record_id: roomRecordId,
    room_id: roomId,
    room_type: getLookupValue(fields['Room Type']) || fields['Room Type'] || '',
    capacity: Number(getLookupValue(fields['Capacity']) || 0),
    fill_priority: Number(getLookupValue(fillPriorityRaw) || 50),
    private_priority: Number(getLookupValue(privatePriorityRaw) || 50),
    gender_strategy: String(getLookupValue(fields['Gender Strategy']) || 'Flexible'),
    often_used_by_operator: boolValue(fields['Often used By Operator']),
    active: boolValue(fields['Active']),
    fields
  };

  if (roomRecordId) {
    roomsByRecordId[roomRecordId] = roomData;
  }

  if (roomId) {
    roomsByRoomId[String(roomId)] = roomData;
  }
}

// Normalize active beds and join room metadata.
const allBeds = bedsRaw.map(item => {
  const fields = item.json.fields || item.json;

  const roomRecordId = Array.isArray(fields['Room'])
    ? fields['Room'][0]
    : fields['Room'];

  const roomIdFromBed = getLookupValue(fields['Room ID']);

  const roomMeta =
    roomsByRecordId[roomRecordId] ||
    roomsByRoomId[String(roomIdFromBed || '')] ||
    {};

  const roomId =
    roomMeta.room_id ||
    roomIdFromBed ||
    '';

  return {
    record_id: item.json.id,
    bed_id: getLookupValue(fields['Bed ID']) || fields['Bed ID'] || '',
    room_record_id: roomRecordId,
    room_id: roomId,
    room_name: roomMeta.room_id || `Room ${String(roomId).replace('R', '')}`,
    planning_row_label: fields['Planning Row Label'],
    bed_number: Number(fields['Bed Number'] || 0),
    bed_label: fields['Bed Label'] || '',
    room_type: roomMeta.room_type || '',
    capacity: Number(roomMeta.capacity || 0),
    fill_priority: Number(roomMeta.fill_priority || 50),
    private_priority: Number(roomMeta.private_priority || 50),
    gender_strategy: String(roomMeta.gender_strategy || 'Flexible'),
    often_used_by_operator: boolValue(roomMeta.often_used_by_operator),
    room_active: roomMeta.active !== false,
    fields
  };
}).filter(bed => bed.record_id && bed.room_id && bed.room_active);

// Existing occupied beds.
// Only count assignments that overlap this booking's requested dates.
const occupiedBedIds = new Set();

for (const item of assignmentsRaw) {
  const fields = item.json.fields || item.json;

  const bed = getLookupValue(fields['Bed']);

  const assignmentStart =
    getLookupValue(fields['Assignment Start Date']) ||
    getLookupValue(fields['Check In']);

  const assignmentEnd =
    getLookupValue(fields['Assignment End Date']) ||
    getLookupValue(fields['Check Out']);

  const assignmentStatus = String(fields['Status'] || '').trim();

  if (!bed) continue;

  if (
    assignmentStatus === 'Cancelled' ||
    assignmentStatus === 'Expired'
  ) {
    continue;
  }

  // If date fields are missing, be conservative and count it as occupied.
  const assignmentOverlaps =
    !assignmentStart ||
    !assignmentEnd ||
    !session.check_in ||
    !session.check_out ||
    overlaps(session.check_in, session.check_out, assignmentStart, assignmentEnd);

  if (assignmentOverlaps) {
    occupiedBedIds.add(String(bed));
  }
}

const freeBeds = allBeds.filter(bed => {
  return !occupiedBedIds.has(String(bed.record_id));
});

const rooms = {};

for (const bed of freeBeds) {
  if (!rooms[bed.room_id]) {
    rooms[bed.room_id] = {
      room_id: bed.room_id,
      room_name: bed.room_name,
      room_type: bed.room_type,
      capacity: bed.capacity,
      fill_priority: bed.fill_priority,
      private_priority: bed.private_priority,
      gender_strategy: bed.gender_strategy,
      often_used_by_operator: bed.often_used_by_operator,
      beds: []
    };
  }

  rooms[bed.room_id].beds.push(bed);
}

for (const room of Object.values(rooms)) {
  room.beds.sort((a, b) => a.bed_number - b.bed_number);
}

const roomsWithFreeBeds = Object.values(rooms)
  .filter(room => room.beds.length > 0);

const totalFreeBeds = roomsWithFreeBeds.reduce((sum, room) => {
  return sum + room.beds.length;
}, 0);

function scoreRoom(room) {
  if (privatePlacementRequested) {
    return Number(room.private_priority || room.fill_priority || 50);
  }

  return Number(room.fill_priority || 50);
}

function roomAllowedForRequest(room) {
  if (privatePlacementRequested) {
    return isPrivateLikeRoom(room) && room.beds.length >= guestCount;
  }

  if (femalePlacementRequested) {
    return roomIsFemalePreferred(room);
  }

  if (malePlacementRequested) {
    return roomIsMalePreferred(room);
  }

  // Normal shared request: do not show private-like rooms as the first option.
  return !isPrivateLikeRoom(room);
}

let candidateRooms = roomsWithFreeBeds
  .filter(room => room.beds.length >= guestCount)
  .filter(roomAllowedForRequest);

// If female-only was requested but no female-preferred room fits,
// fall back to any non-private room only so the bot can still say there is space.
// Actual assignment may mark review depending on final rooming logic.
if (!candidateRooms.length && femalePlacementRequested) {
  candidateRooms = roomsWithFreeBeds
    .filter(room => room.beds.length >= guestCount)
    .filter(room => !isPrivateLikeRoom(room));
}

// If male-only was requested but no male-preferred room fits,
// fall back to any non-private room only.
if (!candidateRooms.length && malePlacementRequested) {
  candidateRooms = roomsWithFreeBeds
    .filter(room => room.beds.length >= guestCount)
    .filter(room => !isPrivateLikeRoom(room));
}

// For normal shared requests, avoid gender-preferred rooms if flexible rooms are available.
if (
  !privatePlacementRequested &&
  !femalePlacementRequested &&
  !malePlacementRequested
) {
  const flexibleCandidates = candidateRooms.filter(room =>
    !roomIsFemalePreferred(room) &&
    !roomIsMalePreferred(room)
  );

  if (flexibleCandidates.length > 0) {
    candidateRooms = flexibleCandidates;
  }
}

candidateRooms.sort((a, b) => {
  return scoreRoom(a) - scoreRoom(b);
});

const availableRooms = roomsWithFreeBeds
  .sort((a, b) => scoreRoom(a) - scoreRoom(b))
  .map(room => ({
    room_id: room.room_id,
    room_name: room.room_name,
    free_beds: room.beds.length,
    gender_strategy: room.gender_strategy,
    fill_priority: room.fill_priority
  }));

if (!candidateRooms.length) {
  // If no single room fits, but enough total beds exist, availability is still true.
  // The later Assign Beds workflow can split the group across rooms if allowed.
  if (totalFreeBeds >= guestCount && !privatePlacementRequested) {
    return [{
      json: {
        ...data,
        availability_found: true,
        multi_room_required: true,
        availability_type: 'multi_room',
        available_rooms: availableRooms,
        selected_room: null,
        selected_beds: [],
        hold_room_name: 'Multiple rooms',
        hold_room_id: '',
        guest_count: guestCount,
        requested_room_type: requestedRoomType,
        room_preference: roomPreference,
        guest_gender_group_type: guestGenderGroup,
        total_free_beds: totalFreeBeds,
        reason: `Enough total beds are available for ${guestCount} guest(s), but not all in one room.`
      }
    }];
  }

  return [{
    json: {
      ...data,
      availability_found: false,
      multi_room_required: false,
      availability_type: 'none',
      available_rooms: availableRooms,
      selected_room: null,
      selected_beds: [],
      hold_room_name: '',
      hold_room_id: '',
      guest_count: guestCount,
      requested_room_type: requestedRoomType,
      room_preference: roomPreference,
      guest_gender_group_type: guestGenderGroup,
      total_free_beds: totalFreeBeds,
      reason: `Only ${totalFreeBeds} suitable free bed(s) available for ${guestCount} guest(s) from ${session.check_in} to ${session.check_out}.`
    }
  }];
}

const selectedRoom = candidateRooms[0];
const selectedBeds = selectedRoom.beds.slice(0, guestCount);

return [{
  json: {
    ...data,
    availability_found: true,
    multi_room_required: false,
    availability_type: 'single_room',
    available_rooms: availableRooms,
    selected_room: {
      room_id: selectedRoom.room_id,
      room_name: selectedRoom.room_name,
      gender_strategy: selectedRoom.gender_strategy,
      fill_priority: selectedRoom.fill_priority
    },
    selected_beds: selectedBeds,
    hold_room_name: selectedRoom.room_name,
    hold_room_id: selectedRoom.room_id,
    guest_count: guestCount,
    requested_room_type: requestedRoomType,
    room_preference: roomPreference,
    guest_gender_group_type: guestGenderGroup,
    total_free_beds: totalFreeBeds,
