const input = $input.first().json;

// Test input path
if (input.phone && input.guest_message) {
  return [
    {
      json: {
        source: input.source || 'test',
        phone: input.phone,
        guest_message: input.guest_message,
        whatsapp_message_id: input.whatsapp_message_id || '',
        ignore: false,
        raw: input
      }
    }
  ];
}

// Meta WhatsApp webhook path
const value = input.body?.entry?.[0]?.changes?.[0]?.value;
const message = value?.messages?.[0];

// Real inbound guest message
if (message) {
  const from = message.from || '';

  const text =
    message.text?.body ||
    message.button?.text ||
    message.interactive?.button_reply?.title ||
    message.interactive?.list_reply?.title ||
    '';

  return [
    {
      json: {
        source: 'whatsapp',
        phone: from.startsWith('+') ? from : `+${from}`,
        guest_message: text,
        whatsapp_message_id: message.id || '',
        ignore: !text,
        raw: input
      }
    }
  ];
}

// Meta delivery/read/sent status webhook
const status = value?.statuses?.[0];

if (status) {
  return [
    {
      json: {
        source: 'whatsapp_status',
        phone: status.recipient_id ? `+${status.recipient_id}` : '',
        guest_message: '',
        whatsapp_message_id: status.id || '',
        status_type: status.status || '',
        ignore: true,
        raw: input
      }
    }
  ];
}

// Anything else from Meta: ignore
return [
  {
    json: {
      source: 'unknown_webhook',
      phone: '',
      guest_message: '',
      whatsapp_message_id: '',
      ignore: true,
      raw: input
    }
  }
];

