const data = $input.first().json;
const session = data.session || {};

const checkIn = new Date(session.check_in);
const checkOut = new Date(session.check_out);

const stayNights = Math.round((checkOut - checkIn) / (1000 * 60 * 60 * 24));

if (!session.check_in || !session.check_out || !stayNights || stayNights <= 0) {
  return [{
    json: {
      ...data,
      nearby_search_ready: false,
      nearby_options: [],
      nearby_notes: 'Missing valid dates for nearby search.'
    }
  }];
}

function formatDate(date) {
  return date.toISOString().slice(0, 10);
}

const offsets = [-7, -5, -3, -2, -1, 1, 2, 3, 5, 7];

const nearbyOptions = offsets.map(offset => {
  const start = new Date(checkIn);
  start.setDate(start.getDate() + offset);

  const end = new Date(start);
  end.setDate(end.getDate() + stayNights);

  return {
    offset_days: offset,
    check_in: formatDate(start),
    check_out: formatDate(end),
    stay_nights: stayNights
  };
}).filter(option => {
  // Do not suggest dates in the past
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const optionStart = new Date(option.check_in);
  return optionStart >= today;
});

return [{
  json: {
    ...data,
    nearby_search_ready: true,
    original_check_in: session.check_in,
    original_check_out: session.check_out,
    stay_nights: stayNights,
    nearby_options: nearbyOptions
  }
}];

