(() => {
  const options = $('Code - Generate Nearby Date Options').first().json.nearby_options || [];

  if (!options.length) {
    return 'FALSE()';
  }

  const starts = options.map(o => o.check_in).sort();
  const ends = options.map(o => o.check_out).sort();

  const earliestStart = starts[0];
  const latestEnd = ends[ends.length - 1];

  return `AND(
    OR({Status}="Held",{Status}="Confirmed",{Status}="Checked_In"),
    DATETIME_PARSE("${earliestStart}") < {Assignment End Date},
    DATETIME_PARSE("${latestEnd}") > {Assignment Start Date}
  )`;
})()
}}

parameters.jsCode:
const data = $('Code - Generate Nearby Date Options').first().json;

const session = data.session || {};
const nearbyOptions = data.nearby_options || [];

const bedsRaw = $('Search Active Beds - WA').all();
const assignmentsRaw = $('Search Existing Bed Assignments - Nearby').all();
const roomsRaw = $('Search Rooms - Nearby').all();

const guestCount = Math.max(1, Number(session.guest_count || session.guests || 1));

function normalizeSelect(value, fallback = 'unknown') {
  return String(value || fallback)
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_');
}

const requestedRoomType = normalizeSelect(
  session.room_type || session.requested_room_type || 'shared',
  'shared'
);

const roomPreference = normalizeSelect(
  session.room_preference || requestedRoomType,
  requestedRoomType || 'shared'
);

const guestGenderGroup = normalizeSelect(
  session.guest_gender_group_type ||
  session['Guest Gender / Group Type'] ||
  'unknown',
  'unknown'
);

function getLookupValue(value) {
  if (Array.isArray(value)) return value[0];
  return value;
}

function overlaps(aStart, aEnd, bStart, bEnd) {
  return String(aStart) < String(bEnd) && String(bStart) < String(aEnd);
}

function boolValue(value) {
  if (Array.isArray(value)) value = value[0];
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value === 1;
  if (typeof value === 'string') {
    return ['true', 'yes', '1', 'checked', '👍'].includes(value.toLowerCase());
  }
  return false;
}

function getFieldAny(fields, names, fallback = null) {
  for (const name of names) {
    if (
      fields[name] !== undefined &&
      fields[name] !== null &&
      fields[name] !== ''
    ) {
      return fields[name];
    }
  }

  return fallback;
}

function roomGenderStrategy(room) {
  return String(room.gender_strategy || 'Flexible').trim().toLowerCase();
}

function roomTypeValue(room) {
  return String(room.room_type || '').trim().toLowerCase();
}

function roomIsFemalePreferred(room) {
  const strategy = roomGenderStrategy(room);

  return (
    strategy.includes('female') ||
    strategy.includes('women') ||
    strategy.includes('woman') ||
    strategy.includes('ladies') ||
    strategy.includes('girls')
  );
}

function roomIsMalePreferred(room) {
  const strategy = roomGenderStrategy(room);

  return (
    strategy.includes('male') ||
    strategy.includes('men') ||
    strategy.includes('man') ||
    strategy.includes('boys')
  );
}

function isPrivateLikeRoom(room) {
  const strategy = roomGenderStrategy(room);
  const type = roomTypeValue(room);

  return (
    strategy.includes('private') ||
    type.includes('private') ||
    type.includes('double') ||
    type.includes('family') ||
    Number(room.capacity || 0) === 2
  );
}

function wantsPrivatePlacement() {
  return [
    requestedRoomType,
    roomPreference
  ].some(value =>
    [
      'private',
      'private_room',
      'double',
      'family_room',
      'family',
      'couple_private'
    ].includes(String(value || '').toLowerCase())
  );
}

function wantsFemalePlacement() {
  return (
    roomPreference === 'female_only' ||
    guestGenderGroup === 'female_group' ||
    guestGenderGroup === 'solo_female'
  );
}

function wantsMalePlacement() {
  return (
    roomPreference === 'male_only' ||
    guestGenderGroup === 'male_group' ||
    guestGenderGroup === 'solo_male'
  );
}

const roomsByRecordId = {};
const roomsByRoomId = {};

for (const item of roomsRaw) {
  const fields = item.json.fields || item.json;

  const roomRecordId = item.json.id;
  const roomId = getLookupValue(fields['Room ID']) || fields['Room ID'] || '';

  const fillPriorityRaw = getFieldAny(fields, [
    'Fill Priority',
    'Fill Priority ',
    'Fill priority',
    'Fill priority '
  ], 50);

  const privatePriorityRaw = getFieldAny(fields, [
    'Private Priority',
    'Private Priority ',
    'Private priority',
    'Private priority '
  ], 50);

  const roomData = {
    record_id: roomRecordId,
    room_id: roomId,
    room_type: getLookupValue(fields['Room Type']) || fields['Room Type'] || '',
    capacity: Number(getLookupValue(fields['Capacity']) || 0),
    fill_priority: Number(getLookupValue(fillPriorityRaw) || 50),
    private_priority: Number(getLookupValue(privatePriorityRaw) || 50),
    gender_strategy: String(getLookupValue(fields['Gender Strategy']) || 'Flexible'),
    often_used_by_operator: boolValue(fields['Often used By Operator']),
    active: boolValue(fields['Active']),
    fields
  };

  if (roomRecordId) roomsByRecordId[roomRecordId] = roomData;
  if (roomId) roomsByRoomId[String(roomId)] = roomData;
}

const allBeds = bedsRaw.map(item => {
  const fields = item.json.fields || item.json;

  const roomRecordId = Array.isArray(fields['Room'])
    ? fields['Room'][0]
    : fields['Room'];

  const roomIdFromBed = getLookupValue(fields['Room ID']);

  const roomMeta =
    roomsByRecordId[roomRecordId] ||
    roomsByRoomId[String(roomIdFromBed || '')] ||
    {};

  const roomId =
    roomMeta.room_id ||
    roomIdFromBed ||
    '';

  return {
    record_id: item.json.id,
    bed_id: getLookupValue(fields['Bed ID']) || fields['Bed ID'] || '',
    room_record_id: roomRecordId,
    room_id: roomId,
    room_name: roomMeta.room_id || `Room ${String(roomId).replace('R', '')}`,
    bed_number: Number(fields['Bed Number'] || 0),
    bed_label: fields['Bed Label'] || '',
    room_type: roomMeta.room_type || '',
    capacity: Number(roomMeta.capacity || 0),
    fill_priority: Number(roomMeta.fill_priority || 50),
    private_priority: Number(roomMeta.private_priority || 50),
    gender_strategy: String(roomMeta.gender_strategy || 'Flexible'),
    often_used_by_operator: boolValue(roomMeta.often_used_by_operator),
    room_active: roomMeta.active !== false,
    fields
  };
}).filter(bed => bed.record_id && bed.room_id && bed.room_active);

const assignments = assignmentsRaw.map(item => {
  const fields = item.json.fields || item.json;

  return {
    bed_record_id: getLookupValue(fields['Bed']),
    start: getLookupValue(fields['Assignment Start Date']) || getLookupValue(fields['Check In']),
    end: getLookupValue(fields['Assignment End Date']) || getLookupValue(fields['Check Out']),
    status: fields['Status']
  };
}).filter(a => a.bed_record_id && a.start && a.end);

function scoreRoom(room) {
  if (wantsPrivatePlacement()) {
    return Number(room.private_priority || room.fill_priority || 50);
  }

  return Number(room.fill_priority || 50);
}

function roomAllowedForRequest(room) {
  if (wantsPrivatePlacement()) {
    return isPrivateLikeRoom(room) && room.beds.length >= guestCount;
  }

  if (wantsFemalePlacement()) {
    return roomIsFemalePreferred(room) || room.beds.length >= guestCount;
  }

  if (wantsMalePlacement()) {
    return roomIsMalePreferred(room) || room.beds.length >= guestCount;
  }

  // For normal shared/unknown requests, avoid reserving gender-preferred rooms
  // when there are flexible options available. Final selection handles this.
  return !isPrivateLikeRoom(room);
}

function findAvailabilityForOption(option) {
  const occupiedBedIds = new Set();

  for (const assignment of assignments) {
    if (
      assignment.status !== 'Cancelled' &&
      assignment.status !== 'Expired' &&
      overlaps(option.check_in, option.check_out, assignment.start, assignment.end)
    ) {
      occupiedBedIds.add(String(assignment.bed_record_id));
    }
  }

  const freeBeds = allBeds.filter(bed => !occupiedBedIds.has(String(bed.record_id)));

  const rooms = {};

  for (const bed of freeBeds) {
    if (!rooms[bed.room_id]) {
      rooms[bed.room_id] = {
        room_id: bed.room_id,
        room_name: bed.room_name,
        room_type: bed.room_type,
        capacity: bed.capacity,
        fill_priority: bed.fill_priority,
        private_priority: bed.private_priority,
        gender_strategy: bed.gender_strategy,
        often_used_by_operator: bed.often_used_by_operator,
        beds: []
      };
    }

    rooms[bed.room_id].beds.push(bed);
  }

  for (const room of Object.values(rooms)) {
    room.beds.sort((a, b) => a.bed_number - b.bed_number);
  }

  let candidateRooms = Object.values(rooms)
    .filter(room => room.beds.length >= guestCount)
    .filter(roomAllowedForRequest);

  // For normal shared requests, prefer flexible/mixed rooms first if available.
  if (
    !wantsPrivatePlacement() &&
    !wantsFemalePlacement() &&
    !wantsMalePlacement()
  ) {
    const flexibleCandidates = candidateRooms.filter(room =>
      !roomIsFemalePreferred(room) &&
      !roomIsMalePreferred(room)
    );

    if (flexibleCandidates.length > 0) {
      candidateRooms = flexibleCandidates;
    }
  }

  candidateRooms.sort((a, b) => {
    return scoreRoom(a) - scoreRoom(b);
  });

  if (!candidateRooms.length) {
    return null;
  }

  const selectedRoom = candidateRooms[0];

  return {
    check_in: option.check_in,
    check_out: option.check_out,
    stay_nights: option.stay_nights,
    offset_days: option.offset_days,
    room_id: selectedRoom.room_id,
    room_name: selectedRoom.room_name,
    free_beds: selectedRoom.beds.length,
    gender_strategy: selectedRoom.gender_strategy,
    fill_priority: selectedRoom.fill_priority
  };
}

const alternatives = [];

for (const option of nearbyOptions) {
  const result = findAvailabilityForOption(option);

  if (result) {
    alternatives.push(result);
  }
}

alternatives.sort((a, b) => {
  return Math.abs(a.offset_days) - Math.abs(b.offset_days);
});

return [{
  json: {
    ...data,
    nearby_availability_found: alternatives.length > 0,
    nearby_alternatives: alternatives.slice(0, 3)
  }
}];

