parameters.jsCode:
function cleanJson(raw) {
  return String(raw || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (error) {
    return {};
  }
}

function getNodeFields(nodeName) {
  const json = getNodeJson(nodeName);
  return json.fields || {};
}

function normalizeSelect(value, fallback = 'unknown') {
  return String(value || fallback)
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_');
}

function firstNonEmpty(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }

  return '';
}

const inputJson = $input.first()?.json || {};

const aiRoomingInfo = getNodeJson('AI - Classify Rooming Info');
const mergeSessionState = getNodeJson('Merge Session State');
const parseRoute = getNodeJson('Code - Parse Route');
const searchConversation = getNodeJson('Search Conversation');

const searchHoldFields = getNodeFields('Search Hold With Guest Details');
const updateHoldFields = getNodeFields('Update Hold With Guest Details');

const bookingFields = {
  ...searchHoldFields,
  ...updateHoldFields
};

const session =
  mergeSessionState.session ||
  inputJson.session ||
  inputJson.new_state ||
  inputJson.old_state ||
  {};

const raw =
  aiRoomingInfo.text ||
  aiRoomingInfo.output ||
  aiRoomingInfo.response ||
  inputJson.text ||
  inputJson.output ||
  inputJson.response ||
  '{}';

let info = {};

try {
  info = JSON.parse(cleanJson(raw));
} catch (error) {
  info = {};
}

const guestCount = Math.max(
  1,
  Number(
    firstNonEmpty(
      bookingFields['Guest Count'],
      session.guest_count,
      session.guests,
      inputJson.guest_count,
      1
    )
  )
);

const requestedRoomType = normalizeSelect(
  firstNonEmpty(
    bookingFields['Requested Room Type'],
    session.room_type,
    inputJson.room_type,
    'shared'
  ),
  'shared'
);

const roomPreference = normalizeSelect(
  firstNonEmpty(
    bookingFields['Room Preference'],
    session.room_preference,
    inputJson.room_preference,
    requestedRoomType,
    'shared'
  ),
  'shared'
);

const guestGenderGroupType = normalizeSelect(
  firstNonEmpty(
    bookingFields['Guest Gender / Group Type'],
    session.guest_gender_group_type,
    inputJson.guest_gender_group_type,
    info.guest_gender_group,
    'unknown'
  ),
  'unknown'
);

const language =
  firstNonEmpty(
    parseRoute.language,
    searchConversation.fields?.Language,
    session.language,
    inputJson.language,
    'en'
  );

const privateLikeRoomTypes = [
  'private',
  'private_room',
  'double',
  'family_room',
  'family',
  'couple_private',
  'matrimonial'
];

const knownRoomPreferences = [
  'private',
  'private_room',
  'double',
  'family_room',
  'female_only',
  'male_only',
  'mixed_ok',
  'any'
];

const knownGenderGroups = [
  'solo_female',
  'solo_male',
  'female_group',
  'male_group',
  'mixed_group',
  'couple',
  'family',
  'operator_group'
];

const isPrivateLikeBooking =
  privateLikeRoomTypes.includes(requestedRoomType) ||
  privateLikeRoomTypes.includes(roomPreference);

const alreadyHasUsefulRooming =
  knownRoomPreferences.includes(roomPreference) ||
  knownGenderGroups.includes(guestGenderGroupType);

let shouldAsk =
  info.needs_rooming_question === true &&
  requestedRoomType === 'shared' &&
  !isPrivateLikeBooking &&
  !alreadyHasUsefulRooming;

// Important rule:
// If solo male is inferred, do not ask a rooming question.
// We will try to place him in a guys/male-preferred room automatically.
if (guestCount === 1 && info.inferred_lead_gender === 'male') {
  shouldAsk = false;
}

let question = '';

if (shouldAsk && guestCount === 1) {
  if (info.inferred_lead_gender === 'female') {
    question = {
      en: 'Quick one so we can place you in the best room: would you prefer a girls-only room if available, or is mixed okay?',
      de: 'Kurze Frage, damit wir dich im besten Zimmer unterbringen können: Lieber ein Frauen-Zimmer, falls verfügbar, oder ist gemischt okay?',
      es: 'Una pregunta rápida para ubicarte en la mejor habitación: ¿prefieres una habitación solo de chicas si hay, o te va bien una mixta?',
      it: 'Domanda veloce così ti mettiamo nella camera migliore: preferisci una camera solo ragazze se disponibile, o va bene mista?',
      fr: 'Petite question pour te placer dans la meilleure chambre : tu préfères une chambre filles uniquement si dispo, ou une chambre mixte te va ?'
    }[language] || '';
  } else {
    question = {
      en: 'Quick one so we can place you in the best room: do you have any room preference, or is mixed okay?',
      de: 'Kurze Frage, damit wir dich im besten Zimmer unterbringen können: Hast du eine Zimmer-Präferenz oder ist gemischt okay?',
      es: 'Una pregunta rápida para ubicarte en la mejor habitación: ¿tienes alguna preferencia de habitación o te va bien una mixta?',
      it: 'Domanda veloce così ti mettiamo nella camera migliore: hai qualche preferenza per la camera o va bene mista?',
      fr: 'Petite question pour te placer dans la meilleure chambre : tu as une préférence de chambre ou une chambre mixte te va ?'
    }[language] || '';
  }
} else if (shouldAsk && guestCount === 2) {
  question = {
    en: 'Quick one so we can place you in the best room: are you two a couple, two friends, two girls, two guys, or mixed?',
    de: 'Kurze Frage, damit wir euch im besten Zimmer unterbringen können: Seid ihr ein Paar, zwei Freunde, zwei Frauen, zwei Männer oder gemischt?',
    es: 'Una pregunta rápida para ubicaros en la mejor habitación: ¿sois pareja, dos amigos/as, dos chicas, dos chicos o mixto?',
    it: 'Domanda veloce così vi mettiamo nella camera migliore: siete una coppia, due amici/amiche, due ragazze, due ragazzi o misti?',
    fr: 'Petite question pour vous placer dans la meilleure chambre : vous êtes un couple, deux amis, deux filles, deux garçons ou mixtes ?'
  }[language] || '';
} else if (shouldAsk && guestCount === 3) {
  question = {
    en: 'Quick one so we can place you in the best room: is your group mostly girls, mostly guys, or mixed?',
    de: 'Kurze Frage, damit wir euch im besten Zimmer unterbringen können: Seid ihr eher Frauen, eher Männer oder gemischt?',
    es: 'Una pregunta rápida para ubicaros en la mejor habitación: ¿sois más chicas, más chicos o un grupo mixto?',
    it: 'Domanda veloce così vi mettiamo nella camera migliore: siete più ragazze, più ragazzi o un gruppo misto?',
    fr: 'Petite question pour vous placer dans la meilleure chambre : vous êtes plutôt filles, plutôt garçons ou un groupe mixte ?'
  }[language] || '';
} else if (shouldAsk) {
  question = {
    en: 'Quick one so we can place you in the best room: does your group have any room preference, or is any shared setup okay?',
    de: 'Kurze Frage, damit wir euch im besten Zimmer unterbringen können: Habt ihr eine Zimmer-Präferenz oder ist jede geteilte Option okay?',
    es: 'Una pregunta rápida para ubicaros en la mejor habitación: ¿tenéis alguna preferencia de habitación o os va bien cualquier opción compartida?',
    it: 'Domanda veloce così vi mettiamo nella camera migliore: avete qualche preferenza per la camera o va bene qualsiasi opzione condivisa?',
    fr: 'Petite question pour vous placer dans la meilleure chambre : vous avez une préférence de chambre ou toute option partagée vous va ?'
  }[language] || '';
}

return [
  {
    json: {
      ...inputJson,
      ...info,
      guest_count: guestCount,
      requested_room_type: requestedRoomType,
      room_preference: roomPreference,
      guest_gender_group_type: guestGenderGroupType,
      language,
      rooming_question: question,
      should_ask_rooming_question: shouldAsk && !!question
    }
  }
];

function cleanJson(raw) {
  return String(raw || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

const raw =
  $('AI - Classify Rooming Info Reply').first().json.text ||
  $('AI - Classify Rooming Info Reply').first().json.output ||
  $('AI - Classify Rooming Info Reply').first().json.response ||
  '{}';

let parsed = {};

try {
  parsed = JSON.parse(cleanJson(raw));
} catch (e) {
  parsed = {};
}

const guestMessage =
  $('Normalize Incoming Message').first().json.guest_message ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Message Text'] ||
  '';

/**
 * Airtable allowed values for:
 * Guest Gender / Group Type
 *
 * Allowed:
 * unknown
 * solo_female
 * solo_male
 * female_group
 * male_group
 * mixed_group
 * couple
 * family
 * operator_group
 */
let rawGroup = parsed.guest_gender_group || 'unknown';

const groupMap = {
  solo_unknown: 'unknown',
  unknown_two: 'unknown',
  unknown_group: 'unknown',
  male: 'solo_male',
  female: 'solo_female',
  men: 'male_group',
  guys: 'male_group',
  boys: 'male_group',
  women: 'female_group',
  girls: 'female_group',
  mixed: 'mixed_group'
};

rawGroup = groupMap[rawGroup] || rawGroup;

const allowedGroups = [
  'unknown',
  'solo_female',
  'solo_male',
  'female_group',
  'male_group',
  'mixed_group',
  'couple',
  'family',
  'operator_group'
];

const guestGenderGroup = allowedGroups.includes(rawGroup)
  ? rawGroup
  : 'unknown';

/**
 * Airtable allowed values for:
 * Room Preference
 */
let rawPreference = parsed.room_preference || 'unknown';

const preferenceMap = {
  female: 'female_only',
  girls: 'female_only',
  women: 'female_only',
  male: 'male_only',
  guys: 'male_only',
  boys: 'male_only',
  men: 'male_only',
  mixed: 'mixed_ok',
  mixed_room: 'mixed_ok',
  no_preference: 'any',
  whatever: 'any',
  flexible: 'any'
};

rawPreference = preferenceMap[rawPreference] || rawPreference;

const allowedPrefs = [
  'shared',
  'private',
  'female_only',
  'male_only',
  'double',
  'family_room',
  'mixed_ok',
  'any',
  'unknown'
];

const roomPreference = allowedPrefs.includes(rawPreference)
  ? rawPreference
  : 'unknown';

const confidence = Number(parsed.confidence || 0);

return [
  {
    json: {
      guest_gender_group: guestGenderGroup,
      room_preference: roomPreference,
      rooming_notes:
        parsed.rooming_notes ||
        `Guest rooming reply: ${guestMessage}`,
      rooming_confidence: confidence,
      needs_rooming_review:
        !!parsed.needs_human_rooming_review || confidence < 0.5,
      original_rooming_message: guestMessage
    }
  }
];

