function safeJsonParse(value, fallback = {}) {
  if (!value) return fallback;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(value);
  } catch (error) {
    return fallback;
  }
}

const conversation = $('Search Conversation').first().json || {};
const fields = conversation.fields || {};

const session = safeJsonParse(fields['Session State'], {});

const holdId =
  fields['Current Hold ID'] ||
  session.current_hold_id ||
  session.hold_booking_id ||
  session.booking_id ||
  '';

const phone =
  $('Normalize Incoming Message').first().json.phone ||
  ($('Create Inbound Message').isExecuted ? $('Create Inbound Message') : $('Code - DRY RUN Stub (Create Inbound Message)')).first().json.fields?.['Conversation Phone'] ||
  fields.Phone ||
  '';

return [
  {
    json: {
      active_booking_search_hold_id: holdId,
      active_booking_search_phone: phone,
      has_active_booking_hold_id: !!holdId,
      has_active_booking_phone: !!phone
    }
  }
];

function getFirstRealRecord(nodeName) {
  let item;

  try {
    item = $(nodeName).first();
  } catch (error) {
    return null;
  }

  if (!item || !item.json) return null;

  const json = item.json;

  if (json.id && json.fields) {
    return json;
  }

  return null;
}

function safeJsonParse(value, fallback = {}) {
  if (!value) return fallback;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(value);
  } catch (error) {
    return fallback;
  }
}

function normalizeStatus(status) {
  if (!status) return null;
  return String(status).trim();
}

function isActiveBookingStatus(status) {
  const activeStatuses = [
    'Hold',
    'Payment_Pending',
    'Confirmed',
    'Needs_Review'
  ];

  return activeStatuses.includes(normalizeStatus(status));
}

const bookingFromHold =
  getFirstRealRecord('Search Active Booking - Current Hold ID');

const bookingFromPhone =
  getFirstRealRecord('Search Active Booking - Phone');

const activeBooking =
  bookingFromHold ||
  bookingFromPhone ||
  null;

const activeBookingFound = !!activeBooking;

const bookingFields = activeBooking?.fields || {};

const conversationFields =
  $('Search Conversation').first().json.fields || {};

const conversationSession = safeJsonParse(
  conversationFields['Session State'],
  {}
);

const activeBookingStatus =
  normalizeStatus(bookingFields['Status']);

const activeBookingIsUsable =
  activeBookingFound &&
  isActiveBookingStatus(activeBookingStatus);

const activeBookingSummary = activeBookingIsUsable
  ? {
      record_id: activeBooking.id,
      booking_id: bookingFields['Booking ID'] || null,
      status: bookingFields['Status'] || null,

      phone: bookingFields['Phone'] || null,
      guest_name: bookingFields['Guest Name'] || null,
      email: bookingFields['Email'] || null,

      check_in: bookingFields['Check In'] || null,
      check_out: bookingFields['Check Out'] || null,
      guest_count: bookingFields['Guest Count'] || null,

      requested_room_type: bookingFields['Requested Room Type'] || null,
      room_preference: bookingFields['Room Preference'] || null,
      guest_gender_group_type: bookingFields['Guest Gender / Group Type'] || null,

      assignment_status: bookingFields['Assignment Status'] || null,
      availability_check_status: bookingFields['Availability Check Status'] || null,

      needs_rooming_review: bookingFields['Needs Rooming Review'] || false,
      rooming_notes: bookingFields['Rooming Notes'] || '',
      rooming_confidence: bookingFields['Rooming Confidence'] || 0,

