];

function cleanLlmJson(raw) {
  return String(raw || '{}')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function safeJsonParse(value, fallback = {}) {
  if (!value) return fallback;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(cleanLlmJson(value));
  } catch (error) {
    return fallback;
  }
}

